function coreXml(title: string): string {
  const now = new Date().toISOString()
  const safe = title.replace(/[<>&"']/g, '')
  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:dcmitype="http://purl.org/dc/dcmitype/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance">
  <dc:title>${safe}</dc:title>
  <dc:creator>aipresales</dc:creator>
  <cp:lastModifiedBy>aipresales</cp:lastModifiedBy>
  <dcterms:created xsi:type="dcterms:W3CDTF">${now}</dcterms:created>
  <dcterms:modified xsi:type="dcterms:W3CDTF">${now}</dcterms:modified>
</cp:coreProperties>`
}

const APP_XML = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties" xmlns:vt="http://schemas.openxmlformats.org/officeDocument/2006/docPropsVTypes">
  <Application>aipresales</Application>
  <Slides>1</Slides>
  <PresentationFormat>On-screen Show (4:3)</PresentationFormat>
</Properties>`

export async function buildBlankPptxBuffer(title = '新方案'): Promise<Buffer> {
  const zip = new JSZip()
  zip.file('[Content_Types].xml', CONTENT_TYPES)
  zip.file('_rels/.rels', ROOT_RELS)
  zip.file('ppt/presentation.xml', presentationXml(title))
  zip.file('ppt/_rels/presentation.xml.rels', PRESENTATION_RELS)
  zip.file('ppt/slides/slide1.xml', slideXml(title))
  zip.file('ppt/slides/_rels/slide1.xml.rels', SLIDE_RELS)
  zip.file('ppt/slideLayouts/slideLayout1.xml', SLIDE_LAYOUT)
  zip.file('ppt/slideLayouts/_rels/slideLayout1.xml.rels', SLIDE_LAYOUT_RELS)
  zip.file('ppt/slideMasters/slideMaster1.xml', SLIDE_MASTER)
  zip.file('ppt/slideMasters/_rels/slideMaster1.xml.rels', SLIDE_MASTER_RELS)
  zip.file('ppt/theme/theme1.xml', THEME)
  zip.file('docProps/core.xml', coreXml(title))
  zip.file('docProps/app.xml', APP_XML)
  return zip.generateAsync({ type: 'nodebuffer' })
}

export async function writeBlankPptx(absPath: string, title = '新方案'): Promise<void> {
  await mkdir(dirname(absPath), { recursive: true })
  const buffer = await buildBlankPptxBuffer(title)
  await writeFile(absPath, buffer)
}
